## 4. 구현 레이어 설계

### 4-1. GraphQL Controller

**파일 위치:** `graphql/src/main/kotlin/com/maum/backend/controller/profile/ProfileController.kt`

```kotlin
@Controller
class ProfileController(
    private val profileService: ProfileGrpcService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myProfile(@UserId userId: String): ProfileResponse {
        val response = profileService.getProfile(userId)
        return response.profile.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun profile(@Argument userId: String): ProfileResponse? {
        val response = profileService.getProfile(userId)
        return response.profile?.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfile(
        @UserId userId: String,
        @Argument input: UpdateProfileInput,
    ): UpdateProfilePayload {
        val response = profileService.updateProfile(userId, input)
        return if (response.errorsList.isEmpty()) {
            UpdateProfilePayload(profile = response.profile.toResponse(), errors = emptyList())
        } else {
            UpdateProfilePayload(profile = null, errors = response.errorsList.map { it.toErrorResponse() })
        }
    }
}
```

### 4-2. GraphQL Service (gRPC Client)

**파일 위치:** `graphql/src/main/kotlin/com/maum/backend/service/profile/ProfileGrpcService.kt`

```kotlin
@Service
class ProfileGrpcService {
    @GrpcClient("profile-grpc")
    private lateinit var stub: ProfileServiceGrpc.ProfileServiceBlockingStub

    fun getProfile(userId: String): GetProfileResponse {
        val request = GetProfileRequest.newBuilder()
            .setUserId(userId)
            .build()
        return try {
            stub.getProfile(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun updateProfile(userId: String, input: UpdateProfileInput): UpdateProfileResponse {
        val builder = UpdateProfileRequest.newBuilder().setUserId(userId)

        // optional 필드: 전달된 값만 세팅 (PATCH 방식)
        input.nickname?.let { builder.setNickname(it) }
        input.bio?.let { builder.setBio(it) }
        input.profileImageUrl?.let { builder.setProfileImageUrl(it) }
        input.birthDate?.let { builder.setBirthDate(it) }
        input.gender?.let { builder.setGender(Gender.valueOf(it.name)) }

        return try {
            stub.updateProfile(builder.build())
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

### 4-3. gRPC Service 구현 (서버)

**파일 위치:** `{profile-module}/src/main/kotlin/com/maum/backend/controller/ProfileGrpcController.kt`

```kotlin
@GrpcService
class ProfileGrpcController(
    private val profileService: ProfileService,
) : ProfileServiceGrpc.ProfileServiceImplBase() {

    override fun getProfile(
        request: GetProfileRequest,
        responseObserver: StreamObserver<GetProfileResponse>,
    ) {
        val profile = profileService.getProfile(request.userId)
            ?: run {
                responseObserver.onError(
                    Status.NOT_FOUND
                        .withDescription("프로필을 찾을 수 없습니다. userId=${request.userId}")
                        .asException()
                )
                return
            }
        responseObserver.onNext(
            GetProfileResponse.newBuilder().setProfile(profile.toProto()).build()
        )
        responseObserver.onCompleted()
    }

    override fun updateProfile(
        request: UpdateProfileRequest,
        responseObserver: StreamObserver<UpdateProfileResponse>,
    ) {
        val result = profileService.updateProfile(request)
        responseObserver.onNext(result)
        responseObserver.onCompleted()
    }
}
```

